mapper.update:
UPDATE STOCPOHD SET
    VENDOR_RECEIPT_STATUS = #{VENDOR_RECEIPT_STATUS}
    , VENDOR_RECEIPT_DATE = SYSDATE
    , VENDOR_RECEIPT_USER_ID = #{ses.userId}
    , VENDOR_REJECT_RMK = #{VENDOR_REJECT_RMK}
    , MOD_USER_ID = #{ses.userId}
    , MOD_DATE = SYSDATE
WHERE GATE_CD = #{ses.gateCd}
AND BUYER_CD = #{BUYER_CD}
AND PO_NUM = #{PO_NUM}

UPDATE STOCPODT SET
    PROGRESS_CD = #{PROGRESS_CD}
    , MOD_USER_ID = #{ses.userId}
    , MOD_DATE = SYSDATE
WHERE GATE_CD = #{ses.gateCd}
AND BUYER_CD = #{BUYER_CD}
AND PO_NUM = #{PO_NUM}

mapper.select:
SELECT DISTINCT POHD.PO_NUM , POHD.SUBJECT , POHD.VENDOR_CD , GETCOMPANYNAME(POHD.GATE_CD, POHD.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , (POHD.PO_CREATE_DATE, 'YYYY-MM-DD') AS PO_CREATE_DATE , POHD.CUR , POHD.PO_AMT , POHD.VAT_TYPE , POHD.DELIVERY_TYPE , POHD.PAY_TYPE , POHD.CTRL_CD , POHD.CTRL_USER_ID , GETUSERNAME(POHD.GATE_CD, POHD.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , POHD.BUYER_CD , GETCOMPANYNAME(PODT.GATE_CD, PODT.BUYER_CD, #{ses.langCd}) AS BUYER_NM , POHD.DEPT_CD , GETDEPTNAME(POHD.GATE_CD, POHD.BUYER_CD, POHD.DEPT_CD, #{ses.langCd}) AS DEPT_NM , GETBUYERDEPTNAME(POHD.GATE_CD, POHD.BUYER_CD, POHD.DEPT_CD, #{ses.langCd}) AS BUYER_DEPT_NM , POHD.PO_CREATE_TYPE , POHD.RMK_TEXT_NUM , POHD.ATT_FILE_NUM , POHD.INSPECT_USER_ID , GETUSERNAME(POHD.GATE_CD, POHD.INSPECT_USER_ID, #{ses.langCd}) AS INSPECT_USER_NM , POHD.APP_DOC_NUM , POHD.APP_DOC_CNT , POHD.PROGRESS_CD , POHD.SIGN_STATUS FROM STOCPOHD POHD LEFT JOIN STOCPODT PODT ON (PODT.GATE_CD = POHD.GATE_CD AND PODT.BUYER_CD = POHD.BUYER_CD AND PODT.PO_NUM = POHD.PO_NUM AND PODT.DEL_FLAG = '0') WHERE POHD.GATE_CD = #{ses.gateCd}
AND POHD.BUYER_CD = #{BUYER_CD}
AND POHD.BUYER_CD = #{ses.companyCd}
AND POHD.PO_NUM = #{PO_NUM}
AND POHD.APP_DOC_NUM = #{APP_DOC_NUM}
AND POHD.DEL_FLAG = '0'
